            if (currentSession) {
              currentSession.byteLength = lineOffset - currentSession.byteOffset;
              sessions.push(currentSession);
            }

            currentSession = {
              sessionId: match[2],
              timestamp: new Date(match[1]).getTime(),
              byteOffset: lineOffset,
              byteLength: 0,
              entryCount: 1
